    OPS_Tool_Request: "OPS_Tool_Request",

    executor: "executor",
    noop: "noop"
  };

  return map[v] || "OPS_Handoff_Manager";
}

function normalizeActionType(value) {
  const v = String(value || "").trim();

  const map = {
    human_review: "handoff_to_human",
    send_to_handoff: "handoff_to_human",
