  return [{ json: fallback("invalid_case_action") }];
}

if (!allowedActionTypes.includes(actionType)) {
  return [{ json: fallback("invalid_action_type") }];
}

if (Number.isNaN(confidence) || confidence < 0 || confidence > 1) {
  return [{ json: fallback("invalid_confidence") }];
}

targetAgent = normalizeTargetAgent(targetAgent);
actionType = normalizeActionType(actionType);

data.classification.intent = intent;
data.classification.confidence = confidence;
data.classification.target_agent = targetAgent;
data.classification.risk_level = risk;
data.classification.requires_human = data.classification.requires_human === true;

data.routing.target_agent = targetAgent;
data.routing.next_workflow = normalizeTargetAgent(data.routing.next_workflow || targetAgent);
data.routing.fallback_workflow = data.routing.fallback_workflow || "OPS_Handoff_Manager";

data.recommended_action.action_type = actionType;

/*
  Defaults previos al override final.
*/
if (!data.case_decision.service_code) {
  data.case_decision.service_code = "organic_whatsapp";
}

if (!data.case_decision.case_origin_type) {
  data.case_decision.case_origin_type = "organic_whatsapp";
}

if (!data.case_decision.case_type) {
  data.case_decision.case_type = intent === "unknown" ? "consulta_general" : intent;
}

if (!data.case_decision.department) {
  data.case_decision.department = "SAC";
}

if (!data.case_decision.priority) {
