  const v = normalizeText(value);

  const map = {
    greeting: "greeting",
    saludo: "greeting",
    simple_greeting: "greeting",

    quote_request: "quote_request",
    cotizacion: "quote_request",
    cotizar: "quote_request",

    purchase_advice: "purchase_advice",
    asesoria_compra: "purchase_advice",
    sales: "purchase_advice",
    venta: "purchase_advice",
    ventas: "purchase_advice",
    compra: "purchase_advice",

    product_availability: "product_availability",
    stock: "product_availability",

    shipping_question: "shipping_question",
    despacho: "shipping_question",
    envio: "shipping_question",
    shipping: "shipping_question",

    order_status: "order_status",
    pedido: "order_status",
    order: "order_status",
    seguimiento_pedido: "order_status",

    complaint: "complaint",
    reclamo: "complaint",

    warranty: "warranty",
    garantia: "warranty",

    return_or_exchange: "return_or_exchange",
    devolucion: "return_or_exchange",
    cambio: "return_or_exchange",

    postventa_armado: "postventa_armado",
    armado: "postventa_armado",

    postventa_mantencion: "postventa_mantencion",
    mantencion: "postventa_mantencion",
    mantenimiento: "postventa_mantencion",

    postventa_general: "postventa_general",

    campaign_response: "campaign_response",
    review_response: "review_response",

    human_request: "human_request",

    thanks_or_closure: "thanks_or_closure",
    cierre: "thanks_or_closure",
    closure: "thanks_or_closure",
    gracias: "thanks_or_closure",

    customer_rejection: "customer_rejection",
    rechazo: "customer_rejection",
    rejected_by_customer: "customer_rejection",

    opt_out: "opt_out",
    hard_opt_out: "opt_out",
    do_not_contact: "opt_out",

    spam_or_irrelevant: "spam_or_irrelevant",
    tool_request: "tool_request",

    unknown: "unknown"
  };

  return map[v] || "unknown";
}

function normalizeActionType(value) {
  const v = normalizeText(value);

  const map = {
    send_to_agent: "send_to_agent",
    route_to_agent: "send_to_agent",
    agent: "send_to_agent",

    send_to_executor: "send_to_executor",
    execute_response: "send_to_executor",
    reply: "send_to_executor",
    ask_missing_data: "send_to_executor",

    send_to_handoff: "send_to_handoff",
    handoff_to_human: "send_to_handoff",
    human_review: "send_to_handoff",
    handoff: "send_to_handoff",

    close_candidate: "close_candidate",
    close_case: "close_candidate",

    no_action: "no_action",
    noop: "no_action",

    tool_request: "tool_request"
  };

  return map[v] || "send_to_handoff";
}

function isGreetingText(text) {
  const t = normalizeText(text);

  const greetings = new Set([
    "hola",
    "holaa",
    "hola hola",
    "buenas",
    "buen dia",
    "buenos dias",
    "buena",
    "buenas tardes",
    "buenas noches",
    "hello",
    "hi",
    "hey"
  ]);

  return greetings.has(t);
}

function isExplicitClosureText(text) {
  const t = normalizeText(text);

  const patterns = [
    "gracias",
    "muchas gracias",
    "no gracias",
    "quedamos listos",
    "estamos listos",
    "listo gracias",
    "eso era",
    "eso seria",
    "era eso",
    "no necesito nada mas",
    "no me interesa",
    "ya no me interesa"
  ];

  return patterns.some(p => t.includes(normalizeText(p)));
}

function isHardOptOutText(text) {
  const t = normalizeText(text);

  const patterns = [
    "no me escriban mas",
    "no me escribas mas",
    "dejen de escribirme",
    "eliminar mi numero",
    "borrar mi numero",
    "no quiero que me contacten",
    "stop"
  ];

  return patterns.some(p => t.includes(normalizeText(p)));
}

function buildSwitchAction({
  route = false,
  execute = false,
  handoff = false,
  close = false,
  noop = false,
  suppressMail = true,
  suppressHandoff = true,
  blockedReason = null
}) {
  return {
    should_route_to_agent: route,
    should_execute_response: execute,
    should_handoff: handoff,
    should_close_case: close,
    should_noop: noop,
    should_suppress_mail: suppressMail,
    should_suppress_handoff: suppressHandoff,
    blocked_reason: blockedReason
  };
}

const possibleModelOutput =
  get(item, "output") ||
  get(item, "text") ||
  get(item, "response") ||
  get(item, "message.content") ||
  get(item, "choices.0.message.content") ||
  get(item, "raw_model_output") ||
  get(item, "_raw_model_output") ||
  get(item, "data") ||
  null;

const parsedModel =
  parseMaybeJson(possibleModelOutput) ||
  (
    item &&
    typeof item === "object" &&
    (
      item.classification ||
      item.decision ||
      item.case_decision ||
      item.switch_action ||
      item.intent ||
      item.action_type
    )
      ? item
      : {}
  );

const rawInput = firstNonEmptyObject(
  get(parsedModel, "raw_input"),
  get(item, "raw_input"),
  get(item, "input"),
  item
);

const inputEvent = firstNonEmptyObject(
  get(parsedModel, "input_event"),
  get(rawInput, "input_event"),
  get(item, "input_event")
);

const customerContext = firstNonEmptyObject(
  get(parsedModel, "customer_context"),
  get(rawInput, "customer_context"),
  get(item, "customer_context")
);

const caseContext = firstNonEmptyObject(
  get(parsedModel, "case_context"),
  get(rawInput, "case_context"),
  get(item, "case_context")
);

const conversationContext = firstNonEmptyObject(
  get(parsedModel, "conversation_context"),
  get(rawInput, "conversation_context"),
  get(item, "conversation_context")
);

const businessContext = firstNonEmptyObject(
  get(parsedModel, "business_context"),
  get(rawInput, "business_context"),
  get(item, "business_context")
);

const serviceContext = firstNonEmptyObject(
  get(parsedModel, "service_context"),
  get(rawInput, "service_context"),
  get(item, "service_context")
);

const currentText = firstNonNull(
  get(inputEvent, "message_text"),
  get(rawInput, "input_event.message_text"),
  get(businessContext, "current_message_flags.current_message_text"),
  ""
);

const messageType = firstNonNull(
  get(inputEvent, "message_type"),
  get(rawInput, "input_event.message_type"),
  "text"
);

const isGreetingOnly =
  asBool(get(parsedModel, "is_simple_greeting"), false) ||
  asBool(get(businessContext, "current_message_flags.is_greeting_only"), false) ||
  (
    messageType === "text" &&
    isGreetingText(currentText)
  );

const isCustomerRejection =
  asBool(get(parsedModel, "is_customer_rejection"), false);

const isCustomerThanksOrClosure =
  asBool(get(parsedModel, "is_customer_thanks_or_closure"), false) ||
  isExplicitClosureText(currentText);

const isHardOptOut =
  asBool(get(parsedModel, "is_hard_opt_out"), false) ||
  isHardOptOutText(currentText);

const conversationCaseId = firstNonNull(
  get(caseContext, "conversation_case_id"),
  get(caseContext, "case_id"),
  get(rawInput, "case_context.conversation_case_id"),
  get(rawInput, "case_context.case_id")
);

const caseStatus = firstNonNull(
  get(caseContext, "status"),
  get(rawInput, "case_context.status")
);

const lifecycleStatus = firstNonNull(
  get(caseContext, "lifecycle_status"),
  get(rawInput, "case_context.lifecycle_status")
);

const closedAt = firstNonNull(
  get(caseContext, "closed_at"),
  get(rawInput, "case_context.closed_at")
);

const hasActiveCase =
  !!conversationCaseId &&
  !["closed", "archived", "none"].includes(normalizeText(caseStatus)) &&
  !["closed", "archived"].includes(normalizeText(lifecycleStatus)) &&
  !closedAt;

const hasCaseToClose = !!conversationCaseId;

const manualReplyPolicy = firstNonEmptyObject(
  get(parsedModel, "manual_reply_policy"),
  get(conversationContext, "manual_reply_policy")
);

const hasManualReplyPolicy = Object.keys(manualReplyPolicy).length > 0;

const legacyManualReply = asBool(
  firstNonNull(
    get(conversationContext, "manual_reply"),
    get(rawInput, "conversation_context.manual_reply")
  ),
  false
);

const manualReplyBlocksBot =
  hasManualReplyPolicy
    ? (
        asBool(get(manualReplyPolicy, "manual_reply_blocks_bot"), false) &&
        (
          asBool(get(manualReplyPolicy, "has_manual_reply_same_case"), false) ||
          asBool(get(manualReplyPolicy, "has_manual_reply_same_thread"), false)
        )
      )
    : false;

let intent = normalizeIntent(
  firstNonNull(
    get(parsedModel, "intent"),
    get(parsedModel, "classification.intent"),
    get(parsedModel, "decision.intent")
  )
);

let actionType = normalizeActionType(
  firstNonNull(
    get(parsedModel, "action_type"),
    get(parsedModel, "decision.action_type"),
    get(parsedModel, "recommended_action.action_type")
  )
);

let targetAgent = firstNonNull(
  get(parsedModel, "target_agent"),
  get(parsedModel, "classification.target_agent"),
  get(parsedModel, "routing.target_agent"),
  null
);

let confidence = asNumber(
  firstNonNull(
    get(parsedModel, "confidence"),
    get(parsedModel, "classification.confidence"),
    get(parsedModel, "decision.confidence")
  ),
  0
);

let riskLevel = normalizeRisk(
  firstNonNull(
    get(parsedModel, "risk_level"),
    get(parsedModel, "classification.risk_level"),
    get(parsedModel, "decision.risk_level")
  )
);

let requiresHuman = asBool(
  firstNonNull(
    get(parsedModel, "requires_human"),
    get(parsedModel, "classification.requires_human"),
    get(parsedModel, "decision.requires_human")
  ),
  false
);

let allowedToAutoReply = asBool(
  firstNonNull(
    get(parsedModel, "allowed_to_auto_reply"),
    get(parsedModel, "decision.allowed_to_auto_reply"),
    get(parsedModel, "safety.allowed_to_auto_reply")
  ),
  false
);

let blockedReason = firstNonNull(
  get(parsedModel, "blocked_reason"),
  get(parsedModel, "safety.blocked_reason"),
  get(parsedModel, "switch_action.blocked_reason"),
  null
);

let decisionReason = firstNonNull(
  get(parsedModel, "recommended_action.reason"),
  null
);

if (isGreetingOnly) {
  intent = "greeting";
  actionType = "send_to_agent";
  targetAgent = GENERAL_AGENT;
  confidence = Math.max(confidence, 0.9);
  riskLevel = "low";
  requiresHuman = false;
  allowedToAutoReply = !manualReplyBlocksBot;
  blockedReason = manualReplyBlocksBot ? "manual_reply_same_case_or_thread" : null;
  decisionReason = hasActiveCase
    ? "greeting_with_active_case"
    : "greeting_without_active_case";
}

if (
  legacyManualReply === true &&
  !manualReplyBlocksBot &&
  blockedReason === "manual_reply"
) {
  blockedReason = null;
  allowedToAutoReply = true;
}

if (
  isGreetingOnly &&
  (
    intent === "unknown" ||
    blockedReason === "invalid_intent" ||
    actionType === "send_to_handoff"
  )
) {
  intent = "greeting";
  actionType = "send_to_agent";
  targetAgent = GENERAL_AGENT;
  riskLevel = "low";
  requiresHuman = false;
  allowedToAutoReply = true;
  blockedReason = null;
  decisionReason = "invalid_intent_overridden_by_greeting_flag";
}

if (actionType === "close_candidate" && !hasCaseToClose) {
  actionType = "no_action";
  targetAgent = null;
  requiresHuman = false;
  allowedToAutoReply = false;
  blockedReason = "no_active_case_to_close";
  decisionReason = "closure_without_active_case";
}

if (isHardOptOut && !hasCaseToClose) {
  intent = "opt_out";
  actionType = "no_action";
  targetAgent = null;
  requiresHuman = false;
  allowedToAutoReply = false;
  blockedReason = "opt_out_without_active_case";
  decisionReason = "opt_out_without_active_case";
}

if (
  isCustomerThanksOrClosure &&
  !hasCaseToClose &&
  !isGreetingOnly &&
  !isHardOptOut
) {
  intent = "thanks_or_closure";
  actionType = "no_action";
  targetAgent = null;
  requiresHuman = false;
  allowedToAutoReply = false;
  blockedReason = "closure_without_active_case";
  decisionReason = "closure_without_active_case";
}

if (
  intent === "unknown" &&
  !isGreetingOnly &&
  actionType !== "no_action"
) {
  actionType = "send_to_handoff";
  targetAgent = "OPS_Handoff_Manager";
  requiresHuman = true;
  allowedToAutoReply = false;
  riskLevel = "medium";
  blockedReason = blockedReason || "invalid_intent";
  decisionReason = decisionReason || "invalid_intent";
}

let finalAction = null;
let nextWorkflow = null;

if (actionType === "send_to_agent") {
  finalAction = "route_to_agent";
  nextWorkflow = targetAgent || GENERAL_AGENT;
  targetAgent = targetAgent || GENERAL_AGENT;
}

if (actionType === "send_to_executor") {
  finalAction = "reply";
  nextWorkflow = "OPS_Response_Executor";
}

if (actionType === "send_to_handoff") {
  finalAction = "handoff_to_human";
  nextWorkflow = "OPS_Handoff_Manager";
  targetAgent = "OPS_Handoff_Manager";
}

if (actionType === "close_candidate") {
  finalAction = "close_candidate";
  nextWorkflow = "OPS_Case_Closer";
  targetAgent = "OPS_Case_Closer";
}

if (actionType === "tool_request") {
  finalAction = "tool_request";
  nextWorkflow = "OPS_Tool_Request";
  targetAgent = "OPS_Tool_Request";
}

if (actionType === "no_action") {
  finalAction = "no_action";
  nextWorkflow = null;
  targetAgent = null;
}

let switchAction;

if (actionType === "send_to_agent") {
  switchAction = buildSwitchAction({
    route: true,
    execute: false,
    handoff: false,
    close: false,
    noop: false,
    suppressMail: true,
    suppressHandoff: true,
    blockedReason
  });
}

if (actionType === "send_to_executor") {
  switchAction = buildSwitchAction({
    route: false,
    execute: true,
    handoff: false,
    close: false,
    noop: false,
    suppressMail: true,
    suppressHandoff: true,
    blockedReason
  });
}

if (actionType === "send_to_handoff") {
  switchAction = buildSwitchAction({
    route: false,
    execute: false,
    handoff: true,
    close: false,
    noop: false,
    suppressMail: false,
    suppressHandoff: false,
    blockedReason
  });
}

if (actionType === "close_candidate") {
  switchAction = buildSwitchAction({
    route: false,
    execute: false,
    handoff: false,
    close: true,
    noop: false,
    suppressMail: true,
    suppressHandoff: true,
    blockedReason
  });
}

if (actionType === "tool_request") {
  switchAction = buildSwitchAction({
    route: false,
    execute: false,
    handoff: false,
    close: false,
    noop: false,
    suppressMail: true,
    suppressHandoff: true,
    blockedReason
  });

  switchAction.should_tool_request = true;
}

if (actionType === "no_action") {
  switchAction = buildSwitchAction({
    route: false,
    execute: false,
    handoff: false,
    close: false,
    noop: true,
    suppressMail: true,
    suppressHandoff: true,
    blockedReason
  });
}

const department = firstNonNull(
  get(parsedModel, "department"),
  get(parsedModel, "case_decision.department"),
  get(parsedModel, "case_update.department"),
  get(caseContext, "department"),
  "SAC"
);

const serviceCode = firstNonNull(
  get(parsedModel, "service_code"),
  get(parsedModel, "case_decision.service_code"),
  get(parsedModel, "case_update.service_code"),
  get(serviceContext, "service_code"),
  get(caseContext, "service_code"),
  "organic_whatsapp"
);

const caseOriginType = firstNonNull(
  get(parsedModel, "case_origin_type"),
  get(parsedModel, "case_decision.case_origin_type"),
  get(parsedModel, "case_update.case_origin_type"),
  get(serviceContext, "case_origin_type"),
  "organic_whatsapp"
);

const caseType = firstNonNull(
  get(parsedModel, "case_type"),
  get(parsedModel, "case_decision.case_type"),
  get(parsedModel, "case_update.case_type"),
  get(caseContext, "case_type"),
  get(caseContext, "case_topic"),
  "consulta_general"
);

const priority = firstNonNull(
  get(parsedModel, "priority"),
  get(parsedModel, "case_decision.priority"),
  get(parsedModel, "case_update.priority"),
  get(caseContext, "priority"),
  "normal"
);

let caseAction = "continue_or_open";

if (actionType === "send_to_handoff") caseAction = "human_review";
if (actionType === "close_candidate") caseAction = "close_candidate";
if (actionType === "no_action") caseAction = "no_action";
if (actionType === "send_to_agent") caseAction = hasActiveCase ? "continue_case" : "open_or_continue";

const caseStatusForUpdate =
  actionType === "send_to_handoff"
    ? "human_required"
    : actionType === "close_candidate"
      ? "closed"
      : hasActiveCase
        ? caseStatus || "open"
        : "open";

const result = {
  orchestrator: {
    name: ORCHESTRATOR_NAME,
    version: ORCHESTRATOR_VERSION
  },

  classification: {
    intent,
    confidence,
    target_agent: targetAgent,
    risk_level: riskLevel,
    requires_human: requiresHuman
  },

  decision: {
    action_type: actionType,
    requires_human: requiresHuman,
    confidence,
    risk_level: riskLevel,
    allowed_to_auto_reply: allowedToAutoReply
  },

  message: {
    channel: "whatsapp",
    text: firstNonNull(get(parsedModel, "message.text"), ""),
    template_required: asBool(get(parsedModel, "message.template_required"), false)
  },

  case_decision: {
    case_action: caseAction,
    department,
    service_code: serviceCode,
    case_origin_type: caseOriginType,
    case_type: caseType,
    priority
  },

  case_update: {
    case_action: caseAction,
    department,
    service_code: serviceCode,
    case_origin_type: caseOriginType,
    case_type: caseType,
    priority,
    status: caseStatusForUpdate,
    close_reason: actionType === "close_candidate" ? caseType : null,
    suppress_mail: switchAction.should_suppress_mail,
    suppress_handoff: switchAction.should_suppress_handoff,
    do_not_contact: isHardOptOut,
    rejection_detected: isCustomerRejection,
    source_table: firstNonNull(get(serviceContext, "source_table"), get(caseContext, "source_table")),
    source_id: firstNonNull(get(serviceContext, "source_id"), get(caseContext, "source_id")),
    id_order: firstNonNull(get(serviceContext, "id_order"), get(caseContext, "id_order")),
    id_customer: firstNonNull(get(serviceContext, "id_customer"), get(customerContext, "id_customer"), get(caseContext, "id_customer")),
    invoice_number: firstNonNull(get(serviceContext, "invoice_number"), get(customerContext, "invoice_number"), get(caseContext, "invoice_number"))
  },

  missing_data: Array.isArray(get(parsedModel, "missing_data")) ? get(parsedModel, "missing_data") : [],

  recommended_action: {
    action_type: actionType,
    reason: decisionReason
  },

  routing: {
    target_agent: targetAgent,
    next_workflow: nextWorkflow,
    fallback_workflow: actionType === "send_to_handoff" ? "OPS_Handoff_Manager" : null
  },

  safety: {
    allowed_to_auto_reply: allowedToAutoReply,
    blocked_reason: blockedReason,
    suppress_mail: switchAction.should_suppress_mail,
    suppress_handoff: switchAction.should_suppress_handoff,
    do_not_contact: isHardOptOut
  },

  switch_action: switchAction,

  target_agent: targetAgent,
  next_workflow: nextWorkflow,
  route_to: nextWorkflow,
  routing_target: targetAgent,

  final_action: finalAction,
  action_type: actionType,
  requires_human: requiresHuman,
  allowed_to_auto_reply: allowedToAutoReply,
  intent,
  department,
  service_code: serviceCode,
  case_origin_type: caseOriginType,
  case_type: caseType,
  priority,
  risk_level: riskLevel,

  explicit_intent_shift: firstNonNull(get(parsedModel, "explicit_intent_shift"), null),

  is_simple_greeting: isGreetingOnly,
  is_customer_rejection: isCustomerRejection,
  is_hard_opt_out: isHardOptOut,
  is_customer_thanks_or_closure: isCustomerThanksOrClosure,

  input_event: inputEvent,
  service_context: serviceContext,
  customer_context: customerContext,
  business_context: businessContext,
  case_context: caseContext,
  conversation_context: conversationContext,
  risk_flags: Array.isArray(get(parsedModel, "risk_flags"))
    ? get(parsedModel, "risk_flags")
    : (
        Array.isArray(get(businessContext, "risk_flags"))
          ? get(businessContext, "risk_flags")
          : []
      ),

  manual_reply_policy: hasManualReplyPolicy
    ? manualReplyPolicy
    : {
        has_manual_reply_any: legacyManualReply,
        has_manual_reply_same_case: false,
        has_manual_reply_same_thread: false,
        manual_reply_blocks_bot: false,
        last_manual_reply_at: null,
        minutes_since_last_manual_reply: null,
        block_reason: null,
        source: "legacy_manual_reply_flag_ignored_for_blocking"
      },

  router_consistency: {
    has_active_case: hasActiveCase,
    has_case_to_close: hasCaseToClose,
    is_greeting_only: isGreetingOnly,
    manual_reply_blocks_bot: manualReplyBlocksBot,
    legacy_manual_reply_seen: legacyManualReply,
    lifecycle_inconsistent:
      !!closedAt &&
      !["closed", "archived"].includes(normalizeText(lifecycleStatus)),
    decision_reason: decisionReason
  },

  resolver_meta: safeObject(get(parsedModel, "resolver_meta")),

  _validation_error: false,
  _return_orchestrator_result_at: nowIso(),
  raw_input: rawInput,
  raw_model_output: possibleModelOutput || parsedModel
};

return [{ json: result }];
